"use client";

import Link from "next/link";
import { useMemo, useState } from "react";

type Message = {
  id: number;
  sender: string;
  text: string;
};

type Card = {
  suit: "♠" | "♥" | "♦" | "♣";
  rank: string;
};

const SUITS: Card["suit"][] = ["♠", "♥", "♦", "♣"];
const RANKS = ["A", "K", "Q", "J", "10", "9", "8", "7", "6", "5", "4", "3", "2"];

function createDeck(): Card[] {
  const deck: Card[] = [];
  for (const suit of SUITS) {
    for (const rank of RANKS) {
      deck.push({ suit, rank });
    }
  }
  return deck;
}

function shuffle<T>(array: T[]) {
  const copied = [...array];
  for (let i = copied.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [copied[i], copied[j]] = [copied[j], copied[i]];
  }
  return copied;
}

function drawCards(count: number) {
  return shuffle(createDeck()).slice(0, count);
}

function rollD6() {
  return Math.floor(Math.random() * 6) + 1;
}

export default function PokerRoom({ roomId }: { roomId: string }) {
  const [name, setName] = useState("플레이어");
  const [chatInput, setChatInput] = useState("");
  const [messages, setMessages] = useState<Message[]>([
    { id: 1, sender: "시스템", text: "방에 입장했습니다." },
  ]);
  const [lastDice, setLastDice] = useState<number | null>(null);
  const [hand, setHand] = useState<Card[]>(() => drawCards(5));

  const pot = 120;

  const players = useMemo(
    () => [
      { id: "p1", name: name || "플레이어", chips: 980, status: "대기" },
      { id: "p2", name: "상대 1", chips: 1000, status: "대기" },
      { id: "p3", name: "상대 2", chips: 1000, status: "대기" },
    ],
    [name]
  );

  const sendMessage = () => {
    const text = chatInput.trim();
    if (!text) return;

    setMessages((prev) => [
      ...prev,
      {
        id: Date.now(),
        sender: name || "플레이어",
        text,
      },
    ]);
    setChatInput("");
  };

  const handleRollD6 = () => {
    const value = rollD6();
    setLastDice(value);

    setMessages((prev) => [
      ...prev,
      {
        id: Date.now(),
        sender: "시스템",
        text: `${name || "플레이어"} 님이 d6을 굴려 ${value} 이(가) 나왔습니다.`,
      },
    ]);
  };

  const handleRedraw = () => {
    setHand(drawCards(5));
  };

  return (
    <main
      style={{
        minHeight: "100vh",
        background: "#0f172a",
        color: "white",
        padding: 24,
      }}
    >
      <div style={{ maxWidth: 1200, margin: "0 auto" }}>
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            gap: 16,
            alignItems: "center",
            marginBottom: 24,
            flexWrap: "wrap",
          }}
        >
          <div>
            <h1 style={{ margin: 0, fontSize: 32 }}>Poker Room</h1>
            <p style={{ marginTop: 8, color: "#94a3b8" }}>roomId: {roomId}</p>
          </div>

          <Link
            href="/"
            style={{
              textDecoration: "none",
              background: "white",
              color: "black",
              padding: "10px 14px",
              borderRadius: 12,
              fontWeight: 700,
            }}
          >
            로비로
          </Link>
        </div>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1.2fr 0.8fr",
            gap: 20,
          }}
        >
          <section
            style={{
              background: "#1e293b",
              border: "1px solid #334155",
              borderRadius: 20,
              padding: 20,
            }}
          >
            <h2 style={{ marginTop: 0 }}>테이블</h2>

            <div style={{ marginBottom: 16 }}>
              <label
                htmlFor="playerName"
                style={{ display: "block", marginBottom: 8, color: "#cbd5e1" }}
              >
                내 이름
              </label>
              <input
                id="playerName"
                value={name}
                onChange={(e) => setName(e.target.value)}
                style={{
                  width: 240,
                  height: 40,
                  borderRadius: 10,
                  border: "1px solid #475569",
                  background: "#0f172a",
                  color: "white",
                  padding: "0 10px",
                }}
              />
            </div>

            <div
              style={{
                display: "grid",
                gridTemplateColumns: "repeat(3, minmax(0, 1fr))",
                gap: 12,
                marginBottom: 20,
              }}
            >
              {players.map((p) => (
                <div
                  key={p.id}
                  style={{
                    background: "#0f172a",
                    border: "1px solid #334155",
                    borderRadius: 16,
                    padding: 14,
                  }}
                >
                  <div style={{ fontWeight: 700 }}>{p.name}</div>
                  <div style={{ color: "#94a3b8", marginTop: 6 }}>칩: {p.chips}</div>
                  <div style={{ color: "#94a3b8", marginTop: 4 }}>{p.status}</div>
                </div>
              ))}
            </div>

            <div
              style={{
                background: "#14532d",
                borderRadius: 24,
                padding: 24,
                border: "2px solid #166534",
              }}
            >
              <div style={{ marginBottom: 16, color: "#dcfce7", fontWeight: 700 }}>
                현재 팟: {pot}
              </div>

              <div style={{ marginBottom: 12, color: "#dcfce7" }}>내 카드</div>

              <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
                {hand.map((card, index) => {
                  const isRed = card.suit === "♥" || card.suit === "♦";

                  return (
                    <div
                      key={`${card.suit}-${card.rank}-${index}`}
                      style={{
                        width: 72,
                        height: 104,
                        borderRadius: 14,
                        background: "white",
                        color: isRed ? "#dc2626" : "#111827",
                        border: "1px solid #cbd5e1",
                        padding: 10,
                        boxSizing: "border-box",
                        display: "flex",
                        flexDirection: "column",
                        justifyContent: "space-between",
                        fontWeight: 700,
                      }}
                    >
                      <div>{card.rank}</div>
                      <div style={{ alignSelf: "flex-end", fontSize: 22 }}>
                        {card.suit}
                      </div>
                    </div>
                  );
                })}
              </div>

              <div style={{ display: "flex", gap: 10, marginTop: 16, flexWrap: "wrap" }}>
                <button
                  onClick={handleRedraw}
                  style={{
                    height: 42,
                    padding: "0 14px",
                    borderRadius: 12,
                    border: "none",
                    background: "white",
                    color: "black",
                    fontWeight: 700,
                    cursor: "pointer",
                  }}
                >
                  카드 다시 뽑기
                </button>

                <button
                  onClick={handleRollD6}
                  style={{
                    height: 42,
                    padding: "0 14px",
                    borderRadius: 12,
                    border: "none",
                    background: "#e2e8f0",
                    color: "black",
                    fontWeight: 700,
                    cursor: "pointer",
                  }}
                >
                  d6 굴리기
                </button>
              </div>

              <div style={{ marginTop: 16, color: "#dcfce7" }}>
                최근 주사위:
                <strong style={{ marginLeft: 8 }}>
                  {lastDice === null ? "-" : lastDice}
                </strong>
              </div>
            </div>
          </section>

          <aside
            style={{
              background: "#1e293b",
              border: "1px solid #334155",
              borderRadius: 20,
              padding: 20,
              display: "flex",
              flexDirection: "column",
              minHeight: 640,
            }}
          >
            <h2 style={{ marginTop: 0 }}>채팅</h2>

            <div
              style={{
                flex: 1,
                overflowY: "auto",
                background: "#0f172a",
                border: "1px solid #334155",
                borderRadius: 16,
                padding: 12,
                marginBottom: 12,
              }}
            >
              {messages.map((msg) => (
                <div
                  key={msg.id}
                  style={{
                    padding: 10,
                    borderRadius: 12,
                    background: "#111827",
                    marginBottom: 8,
                  }}
                >
                  <div style={{ fontWeight: 700, marginBottom: 4 }}>{msg.sender}</div>
                  <div style={{ color: "#d1d5db" }}>{msg.text}</div>
                </div>
              ))}
            </div>

            <div style={{ display: "flex", gap: 8 }}>
              <input
                value={chatInput}
                onChange={(e) => setChatInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") sendMessage();
                }}
                placeholder="메시지를 입력하세요"
                style={{
                  flex: 1,
                  height: 44,
                  borderRadius: 12,
                  border: "1px solid #475569",
                  background: "#0f172a",
                  color: "white",
                  padding: "0 12px",
                }}
              />
              <button
                onClick={sendMessage}
                style={{
                  height: 44,
                  padding: "0 16px",
                  borderRadius: 12,
                  border: "none",
                  background: "white",
                  color: "black",
                  fontWeight: 700,
                  cursor: "pointer",
                }}
              >
                전송
              </button>
            </div>
          </aside>
        </div>
      </div>
    </main>
  );
}